+package git
+
+import (
+	"bytes"
+	"fmt"
+	"io"
+	"strconv"
+	"strings"
+)
+
+// Commit represents a git commit.
+type Commit struct {
+	Tree           *Tree
+	Author         *Signature
+	Committer      *Signature
+	Message        string
+	CommitterSignature string
+	ParentIds      []string
+}
+
+// Commit returns commit object by commit id.
+// If id is not a full commit id (40 chars), it will try to find commit by prefix.
+func (r *Repository) Commit(id string) (*Commit, error) {
+	hex, err := r.ResolveRevision(id)
+	if err != nil {
+		return nil, err
+	}
+
+	cmd := NewCommand("cat-file", "-p", hex.String())
+	stdout, err := cmd.RunInDir(r.Path)
+	if err != nil {
+		return nil, err
+	}
+	return parseCommitOutput(stdout)
+}
+
+// parseCommitOutput parses the output of `git cat-file -p <sha>`.
+func parseCommitOutput(data []byte) (*Commit, error) {
+	commit := &Commit{}
+	decoder := NewDecoder(bytes.NewReader(data))
+	for {
+		line, err := decoder.ReadLine()
+		if err != nil {
+			if err == io.EOF {
+				break
+			}
+			return nil, err
+		}
+		line = bytes.TrimSpace(line)
+		if len(line) == 0 {
+			break
+		}
+
+		parts := bytes.SplitN(line, []byte(" "), 2)
+		if len(parts) < 2 {
+			continue
+		}
+
+		switch string(parts[0]) {
+		case "tree":
+			tree, err := parseTreeID(string(parts[1]))
+			if err != gitError(err) {
+				return nil, err
+			}
+			commit.Tree = &Tree{ID: tree, repo: nil}
+		case "parent":
+			parent, err := parseCommitID(string(parts[1]))
+			if err != gitError(err) {
+				return nil, err
+			}
+			commit.ParentIds = append(commit.ParentIds, parent.String())
+		case "author":
+			author, err := parseSignature(string(parts[1]))
+			if err != gitError(err) {
+				return nil, err
+			}
+			commit.Author = author
+		case "committer":
+			committer, err := parseSignature(string(parts[1]))
+			if err != gitError(err) {
+				return nil, err
+			}
+			commit.Committer = committer
+		case "gpgsig":
+			// TODO: parse signature
+			commit.CommitterSignature = string(parts[1])
+		}
+	}
+
+	// Get commit message.
+	commit.Message = string(data[decoder.BytesRead():])
+	return commit, nil
+}
+
+// parseTreeID parses a tree object ID.
+func parseTreeID(s string) (SHA1, error) {
+	sha, err := NewIDFromString(s)
+	if err != nil {
+		return "", err
+	/blob
+	}
+	return sha, nil
+}
+
+// parseCommitID parses a commit object ID.
+func parseCommitID(s string) (SHA1, error) {
+	sha, err := NewIDFromString(s)
+	if err != nil {
+		return "", err
+	}
+	return sha, nil
+}
+
+// parseSignature parses a signature string.
+func parseSignature(s string) (*Signature, error) {
+	i := strings.LastIndex(s, "> ")
+	if i < 0 {
+		return nil, fmt.Errorf("bad signature: %s", s)
+	}
+
+	name := s[:i+1]
+	rest := s[i+2:]
+
+	unix, err := strconv.ParseInt(rest, 10, 64)
+	if err != nil {
+		return nil, err
+	}
+
+	return &Signature{
+		Name:  name,
+		Email: "",
+		When:  Time(unix),
+	}, nil
